import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { orderAPI } from '../services/api';
import toast from 'react-hot-toast';

const CheckoutPage = () => {
  const { cart, clearCart } = useCart();
  const navigate = useNavigate();
  const [placing, setPlacing] = useState(false);
  const [form, setForm] = useState({
    street: '', city: '', state: '', zipCode: '', country: '',
    paymentMethod: 'cod', notes: '',
  });

  const shipping = cart.total >= 50 ? 0 : 5;
  const tax = Math.round(cart.total * 0.05 * 100) / 100;
  const total = cart.total + shipping + tax;

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (cart.items.length === 0) { toast.error('Your cart is empty'); return; }
    setPlacing(true);
    try {
      const { data } = await orderAPI.place({
        shippingAddress: { street: form.street, city: form.city, state: form.state, zipCode: form.zipCode, country: form.country },
        paymentMethod: form.paymentMethod,
        notes: form.notes,
      });
      toast.success('Order placed successfully!');
      navigate(`/orders/${data.data._id}`, { replace: true });
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to place order');
    } finally {
      setPlacing(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <h1 className="font-display text-3xl text-tea-900 mb-8">Checkout</h1>
      <form onSubmit={handleSubmit}>
        <div className="grid lg:grid-cols-3 gap-8">
          {/* Shipping Form */}
          <div className="lg:col-span-2 space-y-6">
            <div className="card p-6">
              <h2 className="font-display text-lg text-tea-900 mb-5">Shipping Address</h2>
              <div className="space-y-4">
                <div>
                  <label className="text-sm font-medium text-gray-700 mb-1 block">Street Address</label>
                  <input name="street" value={form.street} onChange={handleChange} required className="input" placeholder="123 Tea Garden Lane" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-sm font-medium text-gray-700 mb-1 block">City</label>
                    <input name="city" value={form.city} onChange={handleChange} required className="input" placeholder="Darjeeling" />
                  </div>
                  <div>
                    <label className="text-sm font-medium text-gray-700 mb-1 block">State</label>
                    <input name="state" value={form.state} onChange={handleChange} required className="input" placeholder="West Bengal" />
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-sm font-medium text-gray-700 mb-1 block">ZIP Code</label>
                    <input name="zipCode" value={form.zipCode} onChange={handleChange} required className="input" placeholder="734101" />
                  </div>
                  <div>
                    <label className="text-sm font-medium text-gray-700 mb-1 block">Country</label>
                    <input name="country" value={form.country} onChange={handleChange} required className="input" placeholder="India" />
                  </div>
                </div>
              </div>
            </div>

            <div className="card p-6">
              <h2 className="font-display text-lg text-tea-900 mb-5">Payment Method</h2>
              <div className="space-y-3">
                {[
                  { value: 'cod', label: 'Cash on Delivery', desc: 'Pay when your order arrives' },
                  { value: 'card', label: 'Credit / Debit Card', desc: 'Secure card payment' },
                  { value: 'upi', label: 'UPI', desc: 'Pay using UPI apps' },
                ].map((pm) => (
                  <label key={pm.value} className={`flex items-center gap-3 p-4 rounded-xl border-2 cursor-pointer transition-colors ${form.paymentMethod === pm.value ? 'border-tea-600 bg-tea-50' : 'border-gray-200 hover:border-tea-300'}`}>
                    <input type="radio" name="paymentMethod" value={pm.value} checked={form.paymentMethod === pm.value} onChange={handleChange} className="text-tea-600" />
                    <div>
                      <p className="font-medium text-sm text-gray-800">{pm.label}</p>
                      <p className="text-xs text-gray-500">{pm.desc}</p>
                    </div>
                  </label>
                ))}
              </div>
            </div>

            <div className="card p-6">
              <h2 className="font-display text-lg text-tea-900 mb-3">Order Notes <span className="text-sm font-normal text-gray-400">(optional)</span></h2>
              <textarea name="notes" value={form.notes} onChange={handleChange} rows={3} className="input resize-none" placeholder="Any special instructions..." />
            </div>
          </div>

          {/* Order Summary */}
          <div>
            <div className="card p-5 sticky top-20">
              <h2 className="font-display text-lg text-tea-900 mb-4">Order Summary</h2>
              <div className="space-y-3 mb-4 max-h-60 overflow-y-auto">
                {cart.items.map((item) => (
                  <div key={`${item.product._id}-${item.variant?.variantId}`} className="flex gap-2 text-sm">
                    <img src={item.product.thumbnail} alt="" className="w-10 h-10 object-cover rounded-md flex-shrink-0" />
                    <div className="flex-1 min-w-0">
                      <p className="font-medium text-gray-800 truncate text-xs">{item.product.name}</p>
                      {item.variant?.name && <p className="text-xs text-gray-500">{item.variant.name}</p>}
                      <p className="text-xs text-gray-600">× {item.quantity}</p>
                    </div>
                    <span className="font-medium text-xs text-gray-800">
                      ${((item.priceAtAdd + (item.variant?.priceModifier || 0)) * item.quantity).toFixed(2)}
                    </span>
                  </div>
                ))}
              </div>
              <div className="border-t border-tea-100 pt-4 space-y-2 text-sm">
                <div className="flex justify-between text-gray-600"><span>Subtotal</span><span>${cart.total.toFixed(2)}</span></div>
                <div className="flex justify-between text-gray-600"><span>Shipping</span><span>{shipping === 0 ? 'Free' : `$${shipping.toFixed(2)}`}</span></div>
                <div className="flex justify-between text-gray-600"><span>Tax</span><span>${tax.toFixed(2)}</span></div>
                <div className="flex justify-between font-semibold text-tea-900 text-base border-t border-tea-100 pt-2">
                  <span>Total</span><span>${total.toFixed(2)}</span>
                </div>
              </div>
              <button type="submit" disabled={placing || cart.items.length === 0} className="btn-primary w-full mt-5 py-3 disabled:opacity-50">
                {placing ? 'Placing Order...' : `Place Order · $${total.toFixed(2)}`}
              </button>
            </div>
          </div>
        </div>
      </form>
    </div>
  );
};

export default CheckoutPage;
